func TestSalesTrafficSpecsSplitFourteenDayWindows(t *testing.T) {
	specs := salesTrafficSpecs("ATV", 30)
	if len(specs) != 3 {
		t.Fatalf("expected 3 chunks, got %d", len(specs))
	}
	for _, spec := range specs {
		start, err := time.Parse(time.RFC3339, spec.StartTime)
		if err != nil {
			t.Fatal(err)
		}
		end, err := time.Parse(time.RFC3339, spec.EndTime)
		if err != nil {
			t.Fatal(err)
		}
		if end.Sub(start) > 14*24*time.Hour+time.Second {
			t.Fatalf("chunk too large: %s to %s", spec.StartTime, spec.EndTime)
		}
	}
}

